#include<bits/stdc++.h>
using namespace std;
int n,ans=0;
int a[5005][5005],k[5005],vis[10005]={false};
void f(int x){
	if(vis[x]==true)return;
    else{
    	for(int i=0;i<k[x];i++){
        	f(a[x][i]-1);
		}vis[x]=true;
	}   
}   
int main(void){
	std::ios::sync_with_stdio(false);
	cin>>n;
	for(int i=0;i<n;i++){
		cin>>k[i];
		for(int j=0;j<k[i];j++)cin>>a[i][j];
	}
	f(0);
	for(int i=0;i<n;i++){
		ans+=vis[i];
	}cout<<ans;
	
	return false;
}
